// notices.component.ts
import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { NoticeService } from '../../services/api.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-notices',
  templateUrl: './notices.component.html'
})
export class NoticesComponent implements OnInit {
  notices: any[] = [];
  form: FormGroup;
  showModal = false; loading = false; saving = false;

  constructor(private svc: NoticeService, public auth: AuthService, private fb: FormBuilder) {
    this.form = this.fb.group({
      title:       ['', Validators.required],
      content:     ['', Validators.required],
      target_role: ['all']
    });
  }

  ngOnInit() { this.load(); }
  load() {
    this.loading = true;
    this.svc.getAll().subscribe({
      next: r => { this.notices = r.data; this.loading = false; },
      error: () => this.loading = false
    });
  }

  save() {
    if (this.form.invalid) return;
    this.saving = true;
    this.svc.create(this.form.value).subscribe({
      next: () => { this.showModal = false; this.saving = false; this.form.reset({ target_role: 'all' }); this.load(); },
      error: () => this.saving = false
    });
  }

  roleClass(r: string) {
    return r === 'student' ? 'bg-info-subtle text-info' : r === 'faculty' ? 'bg-warning-subtle text-warning' : 'bg-success-subtle text-success';
  }
}
<!-- notices.component.html -->
<div class="d-flex justify-content-between align-items-center mb-4">
  <h4 class="fw-bold mb-0"><i class="bi bi-bell me-2 text-primary"></i>Notices & Announcements</h4>
  <button class="btn btn-primary" (click)="showModal=true" *ngIf="auth.isFaculty()">
    <i class="bi bi-plus-circle me-1"></i>Post Notice
  </button>
</div>

<div *ngIf="loading" class="text-center py-5"><div class="spinner-border text-primary"></div></div>

<div class="row g-3" *ngIf="!loading">
  <div class="col-12" *ngFor="let n of notices">
    <div class="card border-0 shadow-sm" style="border-radius:12px;border-left:4px solid #0d6efd!important;">
      <div class="card-body">
        <div class="d-flex justify-content-between align-items-start">
          <div class="flex-grow-1">
            <div class="d-flex align-items-center gap-2 mb-1">
              <h6 class="fw-bold mb-0">{{ n.title }}</h6>
              <span class="badge text-capitalize" [ngClass]="roleClass(n.target_role)">{{ n.target_role }}</span>
            </div>
            <p class="text-muted mb-2">{{ n.content }}</p>
            <div class="text-muted small">
              <i class="bi bi-person me-1"></i>{{ n.posted_by_name }}
              &nbsp;·&nbsp;
              <i class="bi bi-clock me-1"></i>{{ n.created_at | date:'medium' }}
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
  <div class="col-12" *ngIf="!notices.length">
    <div class="text-center py-5 text-muted"><i class="bi bi-bell-slash fs-1 d-block mb-2"></i>No notices posted yet</div>
  </div>
</div>

<!-- Modal -->
<div class="modal fade show d-block" *ngIf="showModal" tabindex="-1" style="background:rgba(0,0,0,0.5);">
  <div class="modal-dialog modal-dialog-centered">
    <div class="modal-content border-0 shadow" style="border-radius:12px;">
      <div class="modal-header border-0"><h5 class="modal-title fw-bold">Post Notice</h5><button class="btn-close" (click)="showModal=false"></button></div>
      <div class="modal-body">
        <form [formGroup]="form">
          <div class="mb-3">
            <label class="form-label fw-semibold">Title</label>
            <input class="form-control" formControlName="title" placeholder="Notice title...">
          </div>
          <div class="mb-3">
            <label class="form-label fw-semibold">Content</label>
            <textarea class="form-control" formControlName="content" rows="4" placeholder="Notice content..."></textarea>
          </div>
          <div class="mb-2">
            <label class="form-label fw-semibold">Target Audience</label>
            <select class="form-select" formControlName="target_role">
              <option value="all">All</option>
              <option value="student">Students Only</option>
              <option value="faculty">Faculty Only</option>
            </select>
          </div>
        </form>
      </div>
      <div class="modal-footer border-0">
        <button class="btn btn-secondary" (click)="showModal=false">Cancel</button>
        <button class="btn btn-primary" (click)="save()" [disabled]="saving">
          <span *ngIf="saving" class="spinner-border spinner-border-sm me-1"></span>Post Notice
        </button>
      </div>
    </div>
  </div>
</div>
